/// Titan Blueprint MCP Server — Model Context Protocol server for AI assistants.
///
/// Exposes Blueprint data (Terrain, Stratagems, AI prompts) to AI assistants
/// like GitHub Copilot and Claude via the MCP (Model Context Protocol).
///
/// The server reads from `.titan/blueprint.json` (generated by
/// `export_blueprint` or auto-exported by ColossusPlugin) and exposes
/// the data as MCP tools that AI assistants can call.
///
/// ## Usage
///
/// Add to your VS Code settings (`.vscode/settings.json`):
///
/// ```json
/// {
///   "github.copilot.chat.mcpServers": {
///     "titan-blueprint": {
///       "command": "dart",
///       "args": [
///         "run",
///         "titan_colossus:blueprint_mcp_server"
///       ],
///       "cwd": "${workspaceFolder}/packages/titan_colossus"
///     }
///   }
/// }
/// ```
///
/// ## Available Tools
///
/// - `get_terrain` — Returns the app's navigation graph (screens + transitions)
/// - `get_stratagems` — Returns auto-generated edge-case test plans
/// - `get_ai_prompt` — Returns a complete AI-ready testing context document
/// - `get_dead_ends` — Returns screens with no outgoing transitions
/// - `get_unreliable_routes` — Returns transitions with low reliability
/// - `get_route_patterns` — Returns all known route patterns
library;

import 'dart:convert';
import 'dart:io';

/// MCP Server for Titan Blueprint data.
///
/// Implements the Model Context Protocol (MCP) over stdio, exposing
/// Blueprint data as tools that AI assistants can invoke.
Future<void> main(List<String> args) async {
  final server = _BlueprintMcpServer();
  await server.run();
}

class _BlueprintMcpServer {
  String _blueprintPath = '.titan/blueprint.json';
  Map<String, dynamic>? _cachedBlueprint;
  DateTime? _lastModified;

  Future<void> run() async {
    // Read JSON-RPC messages from stdin, write responses to stdout
    final lines = stdin
        .transform(utf8.decoder)
        .transform(const LineSplitter());

    await for (final line in lines) {
      if (line.trim().isEmpty) continue;

      try {
        final request = jsonDecode(line) as Map<String, dynamic>;
        final response = await _handleRequest(request);
        if (response != null) {
          stdout.writeln(jsonEncode(response));
        }
      } catch (e) {
        final errorResponse = {
          'jsonrpc': '2.0',
          'error': {'code': -32700, 'message': 'Parse error: $e'},
          'id': null,
        };
        stdout.writeln(jsonEncode(errorResponse));
      }
    }
  }

  Future<Map<String, dynamic>?> _handleRequest(
    Map<String, dynamic> request,
  ) async {
    final method = request['method'] as String?;
    final id = request['id'];

    switch (method) {
      case 'initialize':
        return _handleInitialize(id, request);
      case 'initialized':
        return null; // Notification, no response needed
      case 'tools/list':
        return _handleToolsList(id);
      case 'tools/call':
        return _handleToolsCall(id, request);
      case 'shutdown':
        return {'jsonrpc': '2.0', 'result': null, 'id': id};
      default:
        return {
          'jsonrpc': '2.0',
          'error': {
            'code': -32601,
            'message': 'Method not found: $method',
          },
          'id': id,
        };
    }
  }

  Map<String, dynamic> _handleInitialize(
    dynamic id,
    Map<String, dynamic> request,
  ) {
    // Check for custom blueprint path in initialization options
    final params = request['params'] as Map<String, dynamic>?;
    final initOptions =
        params?['initializationOptions'] as Map<String, dynamic>?;
    if (initOptions != null && initOptions['blueprintPath'] is String) {
      _blueprintPath = initOptions['blueprintPath'] as String;
    }

    return {
      'jsonrpc': '2.0',
      'result': {
        'protocolVersion': '2024-11-05',
        'capabilities': {
          'tools': {'listChanged': false},
        },
        'serverInfo': {
          'name': 'titan-blueprint',
          'version': '1.0.0',
        },
      },
      'id': id,
    };
  }

  Map<String, dynamic> _handleToolsList(dynamic id) {
    return {
      'jsonrpc': '2.0',
      'result': {
        'tools': [
          {
            'name': 'get_terrain',
            'description':
                "Returns the app's navigation graph discovered by Scout. "
                'Includes all screens (Outposts) and transitions (Marches) '
                'with visit counts, dead-end detection, and reliability scores.',
            'inputSchema': {
              'type': 'object',
              'properties': {
                'format': {
                  'type': 'string',
                  'enum': ['json', 'mermaid', 'ai_map'],
                  'description':
                      'Output format: json (structured), mermaid (diagram), '
                      'or ai_map (human-readable summary). Default: ai_map',
                },
              },
            },
          },
          {
            'name': 'get_stratagems',
            'description':
                'Returns auto-generated edge-case test plans (Stratagems) '
                'from the Gauntlet. Each Stratagem targets a specific weakness: '
                'dead ends, low-reliability transitions, orphan screens, etc.',
            'inputSchema': {
              'type': 'object',
              'properties': {
                'route': {
                  'type': 'string',
                  'description':
                      'Optional: filter Stratagems targeting a specific route '
                      'pattern (e.g. /quest/:id). Returns all if omitted.',
                },
              },
            },
          },
          {
            'name': 'get_ai_prompt',
            'description':
                'Returns a complete AI-ready testing context document. '
                'Includes navigation map, dead ends, unreliable routes, '
                'suggested test scenarios, and previous test results. '
                'Paste this into your prompt for full Blueprint context.',
            'inputSchema': {'type': 'object', 'properties': {}},
          },
          {
            'name': 'get_dead_ends',
            'description':
                'Returns screens with no outgoing transitions. These are '
                'screens where users arrive but never navigate away — '
                'potential crash sites or missing back-navigation.',
            'inputSchema': {'type': 'object', 'properties': {}},
          },
          {
            'name': 'get_unreliable_routes',
            'description':
                'Returns transitions (Marches) with low reliability. '
                'These are navigation paths that frequently fail or have '
                'few successful observations.',
            'inputSchema': {'type': 'object', 'properties': {}},
          },
          {
            'name': 'get_route_patterns',
            'description':
                'Returns all known route patterns registered in the '
                'RouteParameterizer (e.g. /quest/:id, /hero/:heroId).',
            'inputSchema': {'type': 'object', 'properties': {}},
          },
        ],
      },
      'id': id,
    };
  }

  Future<Map<String, dynamic>> _handleToolsCall(
    dynamic id,
    Map<String, dynamic> request,
  ) async {
    final params = request['params'] as Map<String, dynamic>?;
    final toolName = params?['name'] as String?;
    final toolArgs =
        params?['arguments'] as Map<String, dynamic>? ?? const {};

    // Load/refresh Blueprint data
    final blueprint = await _loadBlueprint();
    if (blueprint == null) {
      return {
        'jsonrpc': '2.0',
        'result': {
          'content': [
            {
              'type': 'text',
              'text':
                  'No Blueprint data found at $_blueprintPath. '
                  'Run your app with ColossusPlugin(blueprintExportDirectory: '
                  "'.titan') or execute: "
                  'dart run titan_colossus:export_blueprint',
            },
          ],
          'isError': true,
        },
        'id': id,
      };
    }

    final result = switch (toolName) {
      'get_terrain' => _getTerrain(blueprint, toolArgs),
      'get_stratagems' => _getStratagems(blueprint, toolArgs),
      'get_ai_prompt' => _getAiPrompt(blueprint),
      'get_dead_ends' => _getDeadEnds(blueprint),
      'get_unreliable_routes' => _getUnreliableRoutes(blueprint),
      'get_route_patterns' => _getRoutePatterns(blueprint),
      _ => 'Unknown tool: $toolName',
    };

    return {
      'jsonrpc': '2.0',
      'result': {
        'content': [
          {'type': 'text', 'text': result},
        ],
      },
      'id': id,
    };
  }

  // -----------------------------------------------------------------------
  // Tool implementations
  // -----------------------------------------------------------------------

  String _getTerrain(
    Map<String, dynamic> blueprint,
    Map<String, dynamic> args,
  ) {
    final format = args['format'] as String? ?? 'ai_map';

    return switch (format) {
      'mermaid' => blueprint['mermaid'] as String? ?? 'No Mermaid data',
      'ai_map' => blueprint['aiMap'] as String? ?? 'No AI map data',
      'json' => const JsonEncoder.withIndent('  ')
          .convert(blueprint['terrain'] ?? {}),
      _ => 'Unknown format: $format. Use json, mermaid, or ai_map.',
    };
  }

  String _getStratagems(
    Map<String, dynamic> blueprint,
    Map<String, dynamic> args,
  ) {
    final route = args['route'] as String?;
    final stratagems = blueprint['stratagems'] as List<dynamic>? ?? [];

    List<dynamic> filtered = stratagems;
    if (route != null) {
      filtered =
          stratagems.where((s) {
            final startRoute = (s as Map<String, dynamic>)['startRoute'];
            final name = s['name'] as String? ?? '';
            return startRoute == route || name.contains(route);
          }).toList();
    }

    if (filtered.isEmpty) {
      return route != null
          ? 'No Stratagems found for route: $route'
          : 'No Stratagems generated. Ensure sessions have been '
              'recorded and analyzed.';
    }

    final buf = StringBuffer();
    buf.writeln('# Stratagems (${filtered.length})');
    buf.writeln();

    for (final s in filtered) {
      final map = s as Map<String, dynamic>;
      buf.writeln('## ${map['name']}');
      buf.writeln();
      buf.writeln(map['description'] ?? '');
      buf.writeln();
      buf.writeln('**Start route:** `${map['startRoute']}`');
      final tags = map['tags'] as List<dynamic>?;
      if (tags != null && tags.isNotEmpty) {
        buf.writeln('**Tags:** ${tags.join(', ')}');
      }

      final steps = map['steps'] as List<dynamic>?;
      if (steps != null) {
        buf.writeln('**Steps:** ${steps.length}');
        buf.writeln();
        for (var i = 0; i < steps.length; i++) {
          final step = steps[i] as Map<String, dynamic>;
          buf.writeln(
            '${i + 1}. ${step['description'] ?? step['action'] ?? 'Step ${i + 1}'}',
          );
        }
      }
      buf.writeln();
    }

    return buf.toString();
  }

  String _getAiPrompt(Map<String, dynamic> blueprint) {
    // If we have a pre-generated AI prompt on disk, try loading it
    final promptFile = File(
      _blueprintPath.replaceAll('.json', '-prompt.md'),
    );
    if (promptFile.existsSync()) {
      return promptFile.readAsStringSync();
    }

    // Fall back to constructing from Blueprint data
    final buf = StringBuffer();
    buf.writeln('# App Blueprint — AI Test Generation Context');
    buf.writeln();
    buf.writeln('Exported: ${blueprint['exportedAt'] ?? 'unknown'}');
    buf.writeln();

    // AI Map
    final aiMap = blueprint['aiMap'] as String?;
    if (aiMap != null) {
      buf.writeln('## Navigation Map');
      buf.writeln();
      buf.writeln(aiMap);
      buf.writeln();
    }

    // Mermaid
    final mermaid = blueprint['mermaid'] as String?;
    if (mermaid != null) {
      buf.writeln('## Navigation Diagram');
      buf.writeln();
      buf.writeln('```mermaid');
      buf.writeln(mermaid);
      buf.writeln('```');
      buf.writeln();
    }

    // Stratagems summary
    final stratagems = blueprint['stratagems'] as List<dynamic>?;
    if (stratagems != null && stratagems.isNotEmpty) {
      buf.writeln('## Test Scenarios (${stratagems.length})');
      buf.writeln();
      for (final s in stratagems) {
        final map = s as Map<String, dynamic>;
        buf.writeln('- **${map['name']}**: ${map['description'] ?? ''}');
      }
      buf.writeln();
    }

    // Lineage
    final lineage = blueprint['lineage'] as Map<String, dynamic>?;
    if (lineage != null) {
      buf.writeln('## Route Patterns');
      buf.writeln();
      final patterns = lineage['patterns'] as List<dynamic>?;
      if (patterns != null) {
        for (final p in patterns) {
          buf.writeln('- `$p`');
        }
      }
      buf.writeln();
    }

    return buf.toString();
  }

  String _getDeadEnds(Map<String, dynamic> blueprint) {
    final terrain = blueprint['terrain'] as Map<String, dynamic>?;
    if (terrain == null) return 'No terrain data available.';

    final outposts = terrain['outposts'] as Map<String, dynamic>?;
    if (outposts == null || outposts.isEmpty) return 'No screens discovered.';

    final deadEnds = <Map<String, dynamic>>[];
    for (final entry in outposts.entries) {
      final outpost = entry.value as Map<String, dynamic>;
      final exits = outpost['exits'] as List<dynamic>?;
      if (exits == null || exits.isEmpty) {
        deadEnds.add({'route': entry.key, ...outpost});
      }
    }

    if (deadEnds.isEmpty) return 'No dead ends found — all screens have exits.';

    final buf = StringBuffer();
    buf.writeln('# Dead Ends (${deadEnds.length})');
    buf.writeln();
    for (final de in deadEnds) {
      buf.writeln(
        '- `${de['routePattern'] ?? de['route']}` — '
        '${de['observationCount'] ?? 0} visits',
      );
    }
    return buf.toString();
  }

  String _getUnreliableRoutes(Map<String, dynamic> blueprint) {
    final terrain = blueprint['terrain'] as Map<String, dynamic>?;
    if (terrain == null) return 'No terrain data available.';

    final outposts = terrain['outposts'] as Map<String, dynamic>?;
    if (outposts == null) return 'No outpost data available.';

    final unreliable = <Map<String, dynamic>>[];
    for (final entry in outposts.entries) {
      final outpost = entry.value as Map<String, dynamic>;
      final exits = outpost['exits'] as List<dynamic>? ?? [];
      for (final exit in exits) {
        final march = exit as Map<String, dynamic>;
        final observations = march['observationCount'] as int? ?? 0;
        if (observations < 2) {
          unreliable.add(march);
        }
      }
    }

    if (unreliable.isEmpty) {
      return 'No unreliable routes found — all transitions have adequate '
          'observations.';
    }

    final buf = StringBuffer();
    buf.writeln('# Unreliable Routes (${unreliable.length})');
    buf.writeln();
    for (final m in unreliable) {
      buf.writeln(
        '- `${m['fromRoute']}` → `${m['toRoute']}` — '
        '${m['observationCount']} observations, '
        'trigger: ${m['trigger'] ?? 'unknown'}',
      );
    }
    return buf.toString();
  }

  String _getRoutePatterns(Map<String, dynamic> blueprint) {
    final lineage = blueprint['lineage'] as Map<String, dynamic>?;
    if (lineage == null) return 'No lineage data available.';

    final patterns = lineage['patterns'] as List<dynamic>? ?? [];
    if (patterns.isEmpty) return 'No route patterns registered.';

    final buf = StringBuffer();
    buf.writeln('# Route Patterns (${patterns.length})');
    buf.writeln();
    for (final p in patterns) {
      buf.writeln('- `$p`');
    }
    return buf.toString();
  }

  // -----------------------------------------------------------------------
  // Blueprint loading with caching
  // -----------------------------------------------------------------------

  Future<Map<String, dynamic>?> _loadBlueprint() async {
    final file = File(_blueprintPath);
    if (!file.existsSync()) return null;

    final modified = file.lastModifiedSync();
    if (_cachedBlueprint != null && _lastModified == modified) {
      return _cachedBlueprint;
    }

    try {
      final content = await file.readAsString();
      _cachedBlueprint = jsonDecode(content) as Map<String, dynamic>;
      _lastModified = modified;
      return _cachedBlueprint;
    } catch (_) {
      return null;
    }
  }
}
